/* Cleanup: expire all timed-out sessions */
size_t cache_cleanup(void) {
    if (g_cache == NULL) {
        return 0;
    }

    size_t cleaned = 0;
    pthread_mutex_lock(&g_cache->lock);

    for (size_t i = 0; i < MAX_SESSIONS; i++) {
        if (g_cache->sessions[i].state == SESSION_ACTIVE &&
            is_session_expired(&g_cache->sessions[i])) {
            expire_session_internal(&g_cache->sessions[i]);
            cleaned++;
        }
    }

    pthread_mutex_unlock(&g_cache->lock);
    return cleaned;
}

void cache_stats(size_t *active, size_t *expired, size_t *empty) {
    if (g_cache == NULL) {
        if (active) *active = 0;
        if (expired) *expired = 0;
        if (empty) *empty = MAX_SESSIONS;
        return;
    }

    pthread_mutex_lock(&g_cache->lock);
    if (active) *active = g_cache->active_count;
    if (expired) *expired = g_cache->expired_count;
    if (empty) *empty = MAX_SESSIONS - g_cache->active_count - g_cache->expired_count;
    pthread_mutex_unlock(&g_cache->lock);
}

