    /* Create a session with 5 second TTL for demo */
    const char *sid = session_create(5);
    if (sid == NULL) {
        fprintf(stderr, "Failed to create session\n");
        cache_destroy();
        return 1;
    }

    /* We need to copy the session ID since it points into the cache */
    char session_id[SESSION_ID_LEN];
    strncpy(session_id, sid, SESSION_ID_LEN - 1);
    session_id[SESSION_ID_LEN - 1] = '\0';

    printf("Created session: %s\n", session_id);

    /* Set some data */
    if (session_set(session_id, "username", "alice")) {
        printf("Set username = alice\n");
    }
    if (session_set(session_id, "role", "admin")) {
        printf("Set role = admin\n");
    }
    if (session_set(session_id, "email", "alice@example.com")) {
        printf("Set email = alice@example.com\n");
    }

    /* Read data back */
    const char *username = session_get(session_id, "username");
    if (username) {
        printf("Got username = %s\n", username);
    }

